mapper.select:
SELECT * FROM (
SELECT T.*, ROWNUM AS rn FROM (
SELECT item_id,
item_title,
CREATED_AT
FROM shop_board
ORDER BY item_id desc
) T WHERE ROWNUM <= (#{offset}+1) * #{size}
) WHERE rn > #{offset}  * #{size}

  SELECT * FROM (
    SELECT T.*, ROWNUM AS rn FROM (
          SELECT s.item_id,
                 s.item_title,
                 s.item_price,
                 i.image_url
          FROM shop_board s
                   LEFT JOIN image_info i
                             ON s.item_id = i.item_id
          WHERE s.item_image_link IS NOT NULL
          ORDER BY s.item_id DESC
      ) T WHERE ROWNUM <= (#{offset}+1) * #{size}
) WHERE rn > #{offset} * #{size}
